class QueryComplexityValidator {
  constructor(maxDepth = 5, maxComplexity = 1000) {
    this.maxDepth = maxDepth;
    this.maxComplexity = maxComplexity;
  }

  validateQuery(info) {
    const depth = this.calculateDepth(info.fieldNodes[0], info.fragments, 0);
    const complexity = this.calculateComplexity(info.fieldNodes[0], info.fragments, 0);

    if (depth > this.maxDepth) {
      throw new GraphQLError(`Query depth exceeds maximum allowed depth of ${this.maxDepth}`, {
        extensions: { code: 'QUERY_TOO_DEEP' }
      });
    }

    if (complexity > this.maxComplexity) {
      throw new GraphQLError(`Query complexity exceeds maximum allowed complexity of ${this.maxComplexity}`, {
        extensions: { code: 'QUERY_TOO_COMPLEX' }
      });
    }

    return { depth, complexity };
  }

  calculateDepth(node, fragments, currentDepth) {
    if (!node.selectionSet) {
      return currentDepth;
    }

    let maxChildDepth = currentDepth;

    for (const selection of node.selectionSet.selections) {
      if (selection.kind === 'Field') {
        const childDepth = this.calculateDepth(selection, fragments, currentDepth + 1);
        maxChildDepth = Math.max(maxChildDepth, childDepth);
      } else if (selection.kind === 'FragmentSpread') {
        const fragment = fragments[selection.name.value];
        if (fragment) {
          const fragmentDepth = this.calculateDepth(fragment, fragments, currentDepth);
          maxChildDepth = Math.max(maxChildDepth, fragmentDepth);
        }
      } else if (selection.kind === 'InlineFragment') {
        const inlineDepth = this.calculateDepth(selection, fragments, currentDepth);
        maxChildDepth = Math.max(maxChildDepth, inlineDepth);
      }
    }

    return maxChildDepth;
  }

  calculateComplexity(node, fragments, currentComplexity) {
    if (!node.selectionSet) {
      return currentComplexity + 1;
    }

    let totalComplexity = currentComplexity + 1;

    for (const selection of node.selectionSet.selections) {
      if (selection.kind === 'Field') {
        const fieldComplexity = this.getFieldComplexity(selection.name.value);
        totalComplexity += this.calculateComplexity(selection, fragments, fieldComplexity);
      } else if (selection.kind === 'FragmentSpread') {
        const fragment = fragments[selection.name.value];
        if (fragment) {
          totalComplexity += this.calculateComplexity(fragment, fragments, 0);
        }
      } else if (selection.kind === 'InlineFragment') {
        totalComplexity += this.calculateComplexity(selection, fragments, 0);
      }
    }

    return totalComplexity;
  }

  getFieldComplexity(fieldName) {
    const complexityMap = {
      users: 10,
      posts: 10,
      comments: 5,
      user: 5,
      post: 5,
      comment: 3,
    };
    return complexityMap[fieldName] || 1;
  }
}

